import{_ as o,o as a,c as e,ag as r,ah as s}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"集成终端","description":"","frontmatter":{},"headers":[],"relativePath":"features/terminal.md","filePath":"features/terminal.md"}'),l={name:"features/terminal.md"};function n(i,t,c,d,h,p){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="集成终端" tabindex="-1">集成终端 <a class="header-anchor" href="#集成终端" aria-label="Permalink to &quot;集成终端&quot;">​</a></h1><p>集成终端让你无需切换到外部终端工具，直接在 LoongCode 内运行命令行操作。它是真实的 PTY 终端——PTY 即伪终端，是操作系统提供的终端仿真接口。这意味着 <code>vim</code>、<code>top</code>、<code>npm install</code> 这类交互式程序都能正常运行。</p><blockquote><p>相关基础：<a href="/docs/guide/interface-overview.html">界面导览</a></p></blockquote><hr><h2 id="打开终端" tabindex="-1">打开终端 <a class="header-anchor" href="#打开终端" aria-label="Permalink to &quot;打开终端&quot;">​</a></h2><p><strong>方法一</strong>：点击顶部标题栏的<strong>终端</strong>按钮。</p><p><strong>方法二</strong>：按快捷键 <strong>Ctrl+`</strong>（反引号，Tab 键上方）。</p><p>终端面板从中央对话区底部弹出，覆盖在对话区下方，不影响右侧面板的正常使用。再次点击<strong>终端</strong>按钮或按 Ctrl+` 可关闭面板。终端配色会<strong>跟随当前应用主题</strong>（深色 / 浅色 / 护眼）自动切换（v0.9.1 起）。</p><div class="tip custom-block"><p class="custom-block-title">想在终端里继续 AI 对话？</p><p>本页的集成终端是工作区的 <strong>Shell 终端</strong>。若你想把 <strong>AI 对话本身</strong>切换到 CLI 原生的命令行交互界面里继续（续接同一会话），请使用分栏标题栏的<a href="/docs/features/tui-mode.html">终端 TUI 模式</a>（v0.9.8 起）。</p></div><p><img src="'+s+'" alt="截图：集成终端面板从对话区底部弹出，显示 Shell 提示符，标题栏中「终端」按钮处于激活状态"></p><hr><h2 id="多标签页管理" tabindex="-1">多标签页管理 <a class="header-anchor" href="#多标签页管理" aria-label="Permalink to &quot;多标签页管理&quot;">​</a></h2><p>终端面板支持同时开启多个终端会话：</p><ul><li>点击面板顶部的<strong>新建终端</strong>按钮（+ 图标），新开一个独立的终端标签页。</li><li>点击标签页右侧的关闭按钮可<strong>单独关闭</strong>该终端，同时结束其子进程树，不影响其他标签页。</li><li>点击面板右上角的<strong>关闭终端面板</strong>按钮，关闭并结束当前工作区的<strong>所有</strong>终端。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>关闭终端会连同该终端启动的所有子进程一起结束，避免后台进程残留占用目录。</p></div><hr><h2 id="ai-与终端联动" tabindex="-1">AI 与终端联动 <a class="header-anchor" href="#ai-与终端联动" aria-label="Permalink to &quot;AI 与终端联动&quot;">​</a></h2><p>AI（Agent）执行命令时会在当前工作区的终端中运行，你可以实时看到每条命令的完整输出——构建日志、测试结果、安装进度都逐行显示。</p><p>你同样可以在终端里直接输入命令，与 AI 协同工作：比如 AI 写好脚本后，你手动在终端里运行并把结果告诉 AI。</p><hr><h2 id="终端中的可点击链接-v0-8-0-起" tabindex="-1">终端中的可点击链接（v0.8.0 起） <a class="header-anchor" href="#终端中的可点击链接-v0-8-0-起" aria-label="Permalink to &quot;终端中的可点击链接（v0.8.0 起）&quot;">​</a></h2><p>终端输出里出现的网址（如构建日志中的本地服务地址、文档链接）会被识别为可点击链接：</p><ul><li><strong>左键单击</strong>：直接打开链接。本地地址（如 <code>localhost</code> / 内网地址）会在 LoongCode 内置的<a href="/docs/features/browser.html">浏览器标签页</a>中打开，便于就地预览；其它网址在系统默认浏览器中打开。按住 <code>Ctrl</code>（macOS 为 <code>Cmd</code>）单击可强制改用系统浏览器打开。</li><li><strong>右键单击</strong>：弹出菜单，可选择<strong>复制链接地址</strong>、<strong>在侧边栏浏览器中打开</strong>或<strong>在默认浏览器中打开</strong>；若当前有选中的文本，菜单还会提供<strong>复制</strong>选中内容。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>右键菜单依赖鼠标悬停先命中链接。通过键盘上下文菜单键（如 <code>Shift+F10</code>）在链接上唤起菜单时不会拦截，属正常行为。</p></div><hr><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><p>终端继承工作区的环境变量配置。如需添加全局环境变量（对所有任务生效），请前往<strong>设置 → 常规</strong>进行配置；详见<a href="/docs/settings/general.html">设置 → 常规</a>。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解终端之后，接下来看看如何管理 Git 分支、提交代码以及审查改动——前往 <a href="/docs/features/git.html">Git 集成</a>继续学习。</p>',30)])])}const m=o(l,[["render",n]]);export{u as __pageData,m as default};
